use crate::engine::FrfProducer;

fn gcd(mut a: usize, mut b: usize) -> usize {
    while b != 0 {
        let temp = b;
        b = a % b;
        a = temp;
    }
    a
}

// Aligns a per-worker chunk count to the element-stride cache-line boundary
// to keep neighbouring workers off the same 64-byte line. The naive form
// `chunk + epc - rem` has a starvation degeneracy: when the unaligned
// chunk is smaller than the alignment quantum (`elements_per_cache_line`,
// or `epc`), rounding *up* hands one worker the entire fair share of every
// trailing worker. The pathological case is K workers + L elements with
// `L <= K * epc`, e.g. `Vec<PathBuf>` (24-byte stride → epc=8) at K=8/L=8:
// producer-0 takes all 8, producers 1..7 receive empty slices, the call
// runs serially.
//
// Fix: when `chunk < epc`, the per-worker fair share is below the quantum
// — alignment cannot succeed without concentrating work, so we hand back
// the unaligned chunk. Cache-line crosstalk at L ~= K is real but bounded
// (a few coherence stalls); it is strictly preferable to running K-1 of K
// workers idle. Once `chunk >= epc`, normal round-up alignment resumes
// and the false-sharing protection is back in force.
//
// Also clamp `chunk` to `total` first: rounding past the end produces a
// chunk that the caller would have `min`'d back down anyway, but doing
// it here makes the fast-path comparison honest.
fn align_chunk_for<T>(chunk: usize, total: usize) -> usize {
    let size = std::mem::size_of::<T>();
    if size == 0 {
        return chunk;
    }
    let elements_per_cache_line = 64 / gcd(size, 64);
    let chunk = std::cmp::min(chunk, total);
    if chunk < elements_per_cache_line {
        // Degenerate-alignment fast path: returning `chunk` unchanged
        // gives the caller the natural even split. Trade false-sharing
        // protection for parallelism.
        return chunk;
    }
    let remainder = chunk % elements_per_cache_line;
    if remainder == 0 {
        chunk
    } else {
        chunk + elements_per_cache_line - remainder
    }
}

pub struct SliceProducer<'data, T> {
    pub slice: &'data [T],
}

impl<'data, T: Send + Sync> FrfProducer for SliceProducer<'data, T> {
    type Item = &'data T;
    type Iter = std::slice::Iter<'data, T>;

    fn len(&self) -> usize {
        self.slice.len()
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let (left, right) = self.slice.split_at(index);
        (
            SliceProducer { slice: left },
            SliceProducer { slice: right },
        )
    }

    fn into_iter(self) -> Self::Iter {
        self.slice.iter()
    }

    fn align_chunk(&self, chunk: usize) -> usize {
        align_chunk_for::<T>(chunk, self.slice.len())
    }
}

pub struct SliceMutProducer<'data, T> {
    pub slice: &'data mut [T],
}

impl<'data, T: Send> FrfProducer for SliceMutProducer<'data, T> {
    type Item = &'data mut T;
    type Iter = std::slice::IterMut<'data, T>;

    fn len(&self) -> usize {
        self.slice.len()
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let (left, right) = self.slice.split_at_mut(index);
        (
            SliceMutProducer { slice: left },
            SliceMutProducer { slice: right },
        )
    }

    fn into_iter(self) -> Self::Iter {
        self.slice.iter_mut()
    }

    fn align_chunk(&self, chunk: usize) -> usize {
        align_chunk_for::<T>(chunk, self.slice.len())
    }
}

pub struct ChunksMutProducer<'data, T> {
    pub slice: &'data mut [T],
    pub chunk_size: usize,
}

impl<'data, T: Send> FrfProducer for ChunksMutProducer<'data, T> {
    type Item = &'data mut [T];
    type Iter = std::slice::ChunksMut<'data, T>;

    fn len(&self) -> usize {
        if self.chunk_size == 0 || self.slice.is_empty() {
            0
        } else {
            self.slice.len().div_ceil(self.chunk_size)
        }
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let mid_bytes = index * self.chunk_size;
        let limit = std::cmp::min(mid_bytes, self.slice.len());
        let (left, right) = self.slice.split_at_mut(limit);
        (
            ChunksMutProducer {
                slice: left,
                chunk_size: self.chunk_size,
            },
            ChunksMutProducer {
                slice: right,
                chunk_size: self.chunk_size,
            },
        )
    }

    fn into_iter(self) -> Self::Iter {
        self.slice.chunks_mut(self.chunk_size)
    }
}

#[cfg(test)]
mod align_tests {
    use super::*;

    #[repr(C)]
    #[derive(Default, Clone)]
    struct Stride24 {
        _a: u64,
        _b: u64,
        _c: u64,
    }

    #[test]
    fn align_chunk_does_not_starve_when_fair_share_below_quantum() {
        // Reproducer: K=8 workers + L=8 + 24-byte stride. epc = 8.
        // Pre-fix this rounded chunk=1 up to chunk=8, giving producer-0
        // every element. Post-fix we keep chunk=1 so each of the 8
        // producers receives one element.
        let data = vec![Stride24::default(); 8];
        let producer = SliceProducer { slice: &data[..] };
        // Caller asks for ceil(L/K) = 1.
        let aligned = producer.align_chunk(1);
        assert_eq!(
            aligned, 1,
            "align_chunk must not promote a sub-quantum chunk to the full quantum at L<=K*epc"
        );
    }

    #[test]
    fn align_chunk_preserves_alignment_when_fair_share_exceeds_quantum() {
        // L = 64 elements, K = 8 → ceil(L/K) = 8 == epc. Alignment is
        // a no-op (already on the boundary), so we expect the same value
        // back. Confirms the fast-path doesn't fire when not needed.
        let data = vec![Stride24::default(); 64];
        let producer = SliceProducer { slice: &data[..] };
        assert_eq!(producer.align_chunk(8), 8);
    }

    #[test]
    fn align_chunk_rounds_up_when_above_quantum_and_unaligned() {
        // Stride 24, epc = 8, chunk = 9 → must round up to 16.
        let data = vec![Stride24::default(); 256];
        let producer = SliceProducer { slice: &data[..] };
        assert_eq!(producer.align_chunk(9), 16);
    }

    #[test]
    fn parallel_for_each_visits_every_element_at_l_equals_k() {
        // End-to-end: each of L=8 elements must be touched exactly once
        // even with the alignment quantum equal to L. Pre-fix this
        // failed silently because producer-0 still iterated every item;
        // here we assert all writes landed by checking each slot.
        use crate::prelude::{IntoParallelRefMutIterator, ParallelIterator};
        let mut data = vec![0u64; 8];
        // Stride is 8 bytes here (u64), epc = 8, ceil(8/K) = 1 on K>=8 hosts.
        // The bug is generic over any stride dividing 64; u64 is the
        // worst case (epc=8) and reproduces on most hosts.
        data.par_iter_mut().for_each(|x| *x += 1);
        assert!(
            data.iter().all(|&v| v == 1),
            "every element must be visited exactly once, got {:?}",
            data
        );
    }
}
